# scripts/compare_benchmarks.py
import json, sys

def load(path):
    with open(path) as f:
        return {r["name"]: r for r in json.load(f)["results"]}

baseline_path, current_path = sys.argv[1], sys.argv[2]
REGRESSION_THRESHOLD = 0.20  # 20% slower is a regression

baseline = load(baseline_path)
current = load(current_path)

regressions = []
for name, cur in current.items():
    base = baseline.get(name)
    if base is None:
        print(f"NEW: {name} (no baseline)")
        continue
    for metric in ("p95_ms", "ttft_p95_ms"):
        b_val = base.get(metric)
        c_val = cur.get(metric)
        if b_val is None or c_val is None:
            continue
        pct_change = (c_val - b_val) / b_val
        if pct_change > REGRESSION_THRESHOLD:
            regressions.append(
                f"{name}.{metric}: {b_val:.0f}ms → {c_val:.0f}ms "
                f"(+{pct_change:.0%}, threshold {REGRESSION_THRESHOLD:.0%})"
            )
        else:
            print(f"OK  {name}.{metric}: {b_val:.0f}ms → {c_val:.0f}ms ({pct_change:+.0%})")

if regressions:
    print("\nREGRESSIONS DETECTED:")
    for r in regressions:
        print(f"  ✗ {r}")
    sys.exit(1)
print("\nNo regressions detected.")
